// ────────────────────────────────────────────────
// Plantebeskrivelser
// ────────────────────────────────────────────────
export function plantDesc(key) {
  const descs = {
    tomat: 'Tomat (Solanum lycopersicum) er den mest populære hagefrukten i Norge og krever varm sommer. Dyrkes best i drivhus eller mot sydvendt vegg. Fjern sideskudd regelmessig (indeterminate sorter) for å konsentrere energi til fruktsetting. Vann jevnt — ujevn vanning gir blomsterendeåte (BER). Gjødsle ukentlig med tomatgjødsel fra blomstring.',
    agurk: 'Agurk (Cucumis sativus) er enda mer varmekrevende enn tomat og bør dyrkes i drivhus i Norge. Klyp av toppen ved 50 cm for å fremme sideskudd. Høst mens frukten er ung — store agurker hemmer ny fruktsetting.',
    gulrot: 'Gulrot (Daucus carota) trives i dyp, løs, steinfattig jord. Tynn ut til 5 cm tidlig. Tåler lett frost og kan stå i bakken langt utover høsten — frost gir søtere smak. Rotflue er den største trusselen — bruk fiberduk som forebygging.',
    potet: 'Potet (Solanum tuberosum) er en av de mest produktive hagevekstene. Hypp opp jord to ganger for bedre avling og for å hindre grønne poteter. Tørråte (Phytophthora) er den alvorligste sykdommen — overvåk bladene fra juli.',
    gresskar: 'Gresskar (Cucurbita) er storvokst og plasskrevenende men enkel å dyrke. La bare 2-3 frukter per plante utvikle seg. Skallet skal være hardt og stilken tørr og korkaktig ved høsting. Lagres kjølig og tørt i 3-4 måneder.',
    løk: 'Løk (Allium cepa) er enkel fra sett. Slutt å gjødsle fra juli. Høst når 50% av toppene har falt over. Tørk grundig i 2-3 uker før lagring i tørt, kjølig rom.',
    hvitløk: 'Hvitløk (Allium sativum) plantes om høsten og gir avling neste sommer. Fjern blomsterstilker i juni for større løk. Høst når de to nederste bladlagene er gule.',
    purre: 'Purre (Allium porrum) kan høstes langt ut i november og tåler frost. Hypp opp jord rundt stilken for å bleke. Noen sorter kan overvintre.',
    brokkoli: 'Brokkoli (Brassica oleracea) krever mye nitrogen og jevn fuktighet. Høst hoved-hodet mens blomsterknopper er tette og grønne. Etter høsting gir planten mange sideskudd i uker fremover.',
    blomkål: 'Blomkål er mer krevende enn brokkoli. Bind bladene over hodet for å bevare hvitfargen. Høst når hodet er fast, hvitt og kompakt.',
    hodekål: 'Hodekål kan sprekke ved plutselig mye vann etter tørke — vann jevnt. Hvit- og rødkål er gode lagringsgrønnsaker og holder seg kjølig i måneder.',
    rosenkål: 'Rosenkål smaken forbedres etter frost. Høst neden-fra-og-opp ettersom spirene modner fra bunnen. Trenger lang vekstsesong.',
    spinat: 'Spinat (Spinacia oleracea) trekker opp i varme. Sår du i april høster du i mai-juni. Ny sårunde i august for høstspinaten.',
    salat: 'Salat (Lactuca sativa) er en av de raskeste hagevekstene. Kan sås i vinduskarm fra mars. Høst ytterblader kontinuerlig på bladsorter. Bolter i sterk varme.',
    paprika: 'Paprika (Capsicum annuum) passer best i drivhus i Norge. Trenger lang vekstsesong — sow innendørs i januar-februar. Grønn paprika er umodne frukter, rød/gul er modne.',
    squash: 'Squash (Cucurbita pepo) er svært produktiv. Høst mens frukten er ung (15-20 cm) for best smak. Utnøstede frukter vokser til kjempestore courgetter og stopper ny fruktsetting.',
    bønner: 'Bønner (Phaseolus vulgaris) frigjør nitrogen til jorda. Klatrebønner trenger støtte. Høst hyppig — bønnene skal være unge og sprø.',
    erter: 'Erter (Pisum sativum) er blant de aller tidligste sommergrønnsakene. Høst daglig — erter som henger for lenge blir seige.',
    rødbete: 'Rødbete (Beta vulgaris) er enkel og næringsrik. Hele planten er spiselig — bladene som salat. Baby-rødbeter etter 6-7 uker er en delikatesse.',
    pastinakk: 'Pastinakk (Pastinaca sativa) smaken forbedres etter frost. En av de beste lagringsgrønnsakene fra hagen.',
    kålrabi: 'Kålrabi (Brassica oleracea gongylodes) klar på 6-8 uker. Spis bulben ung (6-8 cm) — den blir treaktig om den blir for stor.',
    reddik: 'Reddik (Raphanus sativus) er den raskeste hageveksten — klar på 3-4 uker fra såing. Perfekt for å fylle tomme rader mellom saktevoksende kulturer.',
    mais: 'Mais (Zea mays) trenger varme og sol. Plant i blokk (4x4) for god vindbestøvning. Høst når silkehårene er brune. Mais bør ideelt fra plante til kjele på under 30 minutter.',
    mangold: 'Mangold (Beta vulgaris cicla) tåler varme bedre enn spinat og produserer gjennom hele sommeren. Bladstilkene kommer i rødt, gult og hvitt.',
    asparges: 'Asparges (Asparagus officinalis) — venter 3 år på første høsting, men planten gir i 20 år. Ikke høst de to første årene. Fra år 3: høst i 4-6 uker, la deretter bregnen vokse.',
    rabarbra: 'Rabarbra (Rheum rhabarbarum) er en av de tidligste høstene fra hagen. Kun stilkene er spiselige — bladene er giftige. La aldri mer enn 1/3 av stilkene høstes av gangen.',
    fennikel: 'Fennikel (Foeniculum vulgare) krever varmt vær for å danne ordentlig bulb. Hypp opp jord rundt bulben for å bleke. Trekker opp lett i kaldt og tørt vær.',
    stangselleri: 'Stangselleri (Apium graveolens) er krevende men belønner deg med saftige stilker. Trenger mye vann og næring. Hvit selleriet ved å dekke stilkene de siste ukene.',
    kinakål: 'Kinakål (Brassica rapa pekinensis) bolter lett i varme. Sår du i høysommer (juli) unngår du problemet. Perfekt til wok og kimchi.',
    jordbær: 'Jordbær (Fragaria x ananassa) er blant de mest populære og enkle hagevekstene. Fjern utløpere løpende for å holde energien i fruktsettingen. Bytt ut planter hvert 3-4 år. Jordbærhalm under frukten holder den ren og tørr.',
    bringebær: 'Bringebær (Rubus idaeus) er svært produktivt men sprer seg aggressivt. Plant langs gjerde. Sommersorter bærer på fjorårets skudd — klipp disse ned etter høsting.',
    solbær: 'Solbær (Ribes nigrum) er ekstremt næringsrik (mye C-vitamin). Tåler halvskygge. Beskjær eldre grener for å forny busken. God til saft, syltetøy og frysing.',
    'rips-rød': 'Rød rips (Ribes rubrum) er hardfør og tåler mer skygge enn de fleste bærbusker. De sure røde bærene er rike på pektin og perfekt til gelé og saft.',
    'rips-hvit': 'Hvit rips er en variant av rød rips med mildere, søtere bær. Brukes på samme måte. Fin som delikatesse direkte fra busken.',
    stikkelsbær: 'Stikkelsbær (Ribes uva-crispa) er hardføre og produktive. Umodne grønne bær er syrlige og gode til syltetøy; modne bær er søtere. Mjøldogg er den vanligste sykdommen.',
    bjørnebær: 'Bjørnebær (Rubus fruticosus) er kraftig voksende og krever støtte. Fruktene er store og saftrike. Blomstrer og bærer på toårsskudd som bringebær.',
    aronia: 'Aronia (svartsurbær) er svært hardfør og full av antioksidanter. Bærene er bitre ferske men sødmer etter frost. Best til saft, te og tørking.',
    blåbær: 'Hageblåbær (Vaccinium corymbosum) krever sur jord (pH 4-5). Nett er nærmest obligatorisk mot fugler. Krever kryssbefruktning — plasser minst to sorter nær hverandre. Svært langlivet.',
    hyllebær: 'Hyllebær (Sambucus nigra) er rask-voksende. Hvite blomster i juni til hyldeblomstsaft. Svarte bær i september til saft og syltetøy — ikke spis rå.',
    tyttebær: 'Tyttebær (Vaccinium vitis-idaea) krever sur jord som blåbær. De røde bærene brukes til syltetøy, saft og som tilbehør til kjøtt. Svært langlivet.',
    eple: 'Epletre (Malus domestica) er en av de beste investeringene i hagen. To sorter gir bedre pollinering. Norske sorter som Aroma, Gravenstein og Discovery er hardføre. Beskjær hvert år for god fruktkvalitet. Skurv er den vanligste sykdommen — velg resistente sorter som Topaz.',
    pære: 'Pæretre (Pyrus communis) ligner eple men er noe mer varmekrevende. Conference er mest hardfør og selvfruktbar. Pærer høstes umodne og modnes innendørs. Lagres kjølig.',
    plomme: 'Plommetre (Prunus domestica) er relativt lett å dyrke i norsk klima. Victoriapl omme er den mest populære sorten. Beskjær etter frost-risiko er over.',
    kirsebær: 'Kirsebærtre (Prunus avium) blomstrer vakkert om våren. Netting er nesten obligatorisk — fuglene konkurrerer om bærene.',
    morello: 'Surkirsebær/Morello (Prunus cerasus) er hardere enn søtkirsebær og selvfruktbar. Bærene er utmerkede til saft, syltetøy og likør. Tåler halvskygge.',
    basilikum: 'Basilikum (Ocimum basilicum) er en varme-elsker. Klyp av blomsterstilker kontinuerlig. Søt basilikum er den klassiske sorten; thai-basilikum har mer anis-smak.',
    persille: 'Persille (Petroselinum crispum) spirer sakte (3-4 uker) — bløtlegg frøene i vann natten over. Flatbladpersille er kraftigere og bedre til matlaging. Tåler frost til november.',
    timian: 'Timian (Thymus vulgaris) er en flerårig urt som tåler tørke godt. Klipp tilbake etter blomstring. Kan overvintre ute i sone 5-6 med litt beskyttelse.',
    oregano: 'Oregano (Origanum vulgare) kan overvintre ute. Smaken er sterkest rett før blomstring. Tørking intensiverer den karakteristiske mediterrane aromaen.',
    rosmarin: 'Rosmarin (Salvia rosmarinus) er klimafølsom i Norge. Fuktighet om vinteren dreper den lettere enn kulde. Bring inn i gryte om høsten eller dekk godt med granbar.',
    mynthe: 'Mynte (Mentha) vokser svært aggressivt. Plant ALLTID i gryte eller beholder — ellers tar den over hele bedet. Mange varianter: peppermynte, grønnmynte, marokansk mynte.',
    gressløk: 'Gressløk (Allium schoenoprasum) er den hardeste og enkleste urten. Blomstene i juni er vakre og spiselige. En av de aller første urtene å komme opp om våren.',
    'rose-hybrid': 'Hybridtearoser er de klassiske store enkeltblomsterne. Krever mer stell enn busk- og parkroser. Beskjær kraftig om våren (til 30-40 cm). Vann ved roten — aldri over bladene.',
    'rose-hybrid-ingrid': '"Ingrid Bergman" er en klassisk hybridtearose med dype fløyelrøde blomster. En av de mest populære norske roser. Remonterende. Relativt god motstandsdyktighet mot svartflekk.',
    'rose-hybrid-peace': '"Peace" er en av verdens mest kjente roser. Store krem-gule blomster med rosa kant. Kraftigvoksende sort. Har eksistert siden 1945. Moderat motstandsdyktighet mot sykdom.',
    'rose-busk': 'Buskroser er generelt hardiere og mindre krevende enn hybridtearoser. Blomstrer rikelig uten den intensive beskjæringen. Mange sorter er remonterende.',
    'rose-busk-austin': 'David Austin-roser kombinerer gammeldags blomsterform og duft med moderne remonterende egenskaper. Beskjær til 40-50 cm om våren. Noen sorter er noe sarte i norsk klima.',
    'rose-klatre': 'Klatreroser brukes mot vegger, gitter og pergola. De fleste blomstrer på gammel ved og tåler ikke kraftig beskjæring. Fest skudd horisontalt for mer blomstring.',
    'rose-klatre-newdawn': '"New Dawn" er en av de hardeste klatrerosene for norsk klima. Blekrosa, duftende blomster. Kan bli svært stor (6-8 m). Remonterende. Tåler halvskygge.',
    'rose-klatre-zeph': '"Zéphirine Drouhin" er tornfri, noe som gjør den enkel å jobbe med. Dyp rosa blomster med sterk duft. Remonterende. Noe sensitiv for svartflekk — gi god luftsirkulasjon.',
    'rose-parkrose': 'Parkroser er blant de hardeste rosene — mange utviklet spesielt for skandinavisk klima. Lite sykdomsproblemer. Mange danner vakre nyper om høsten.',
    'rose-ville': 'Villrose (Rosa canina) er den hardeste av alle roser og krever nesten ingen stell. De røde nypene er rike på C-vitamin og brukes til te, saft og syltetøy.',
    akeleie: 'Akeleie (Aquilegia) er en elegant staude med unike sporede blomster. Halvskyggetolererende. Kortlivet (2-3 år) men sår seg fritt og er alltid tilstede i hagen.',
    astilbe: 'Astilbe er perfekt for fuktige skygge- og halvskyggesteder. Fjærformede blomstertopper. Krever aldri tørke. La frøhodene stå om vinteren — de er dekorative med frost.',
    bergenia: 'Bergenia (elefantøre) er en nøysom, vintergrønn staude. Tidlig blomstring i mars-april. Tåler tørke, skygge og kald vinter. En av de mest hardføre staudene.',
    blåklokke: 'Blåklokke (Campanula) finnes i mange former. Blomstrer lenge (juni-august). Klipp ned etter blomstring for ny runde. Noen sorter sprer seg aggressivt.',
    daglilje: 'Daglilje (Hemerocallis) er en nøysom, robust staude. Hver enkelt blomst varer bare én dag, men planten produserer en blomst etter en annen i uker. Finnes i et enormt fargespekter.',
    echinacea: 'Solhat (Echinacea purpurea) har rosa blomster og konisk midtblomst. Trekker bier og sommerfugler. La frøhodene stå gjennom vinteren — fuglene spiser frøene. Meget hardfør.',
    floks: 'Høstfloks (Phlox paniculata) blomstrer fra juli til september med store duftende blomsterskjermer. Mjøldogg kan være et problem — velg resistente sorter.',
    geranium: 'Storkenebb (Geranium) er enkel og blomsterrik. Klipp ned etter blomstring for ny runde. Mange sorter er svært hardføre. Ikke forveksle med Pelargonium (balkong-"geranium").',
    sedum: 'Bergknapp (Sedum/Hylotelephium) er en kraftig høstblomstrende staude. Blomstrer august-oktober og trekker insekter. Ekstremt tørketålende. La blomsterstandene stå til vår.',
    hostas: 'Hostas (funkia) er skyggehagens dronning. Bladene er dens styrke i grønne, blå-grå eller gule farger. Perfekt under trær. Snegl elsker de saftige bladene — sett ut sneglefeller tidlig vår.',
    rudbeckia: 'Gullblomst (Rudbeckia) er en pålitelig høstblomstrende staude med gule blomster. Blomstrer fra juli til frost. Trekker insekter. Sår seg gjerne selv i hagen.',
    kattemynte: 'Kattemynte (Nepeta) er en myk, duftende staude med blå-lilla blomsterstander. Blomstrer lenge, klipp ned ved halvtid for ny runde. Katter kan bli overdrevent begeistret.',
    rhododendron: 'Rhododendron trenger sur jord (pH 4,5-5,5), halvskygge og jevn fuktighet. Grunt rotsystem — dekk med surt bark. Bryt av visne blomsterstander etter blomstring. Unngå gjødsel med kalk.',
    azalea: 'Hagezalea er nær beslektet med rhododendron og trenger sur jord og halvskygge. Blomstrer tidlig og intenst. Dekk med granbar om vinteren de første årene.',
    syrin: 'Syrin (Syringa) blomstrer i mai med karakteristisk sterk duft. Klipp av visne blomsterstander rett etter blomstring. Beskjær aldri i høst eller vinter.',
    forsythia: 'Forsythia (gullregn) er en av de første buskene til å blomstre — gule blomster på bar kvist i april. Beskjær rett etter blomstring (aldri om høsten). Svært hardfør.',
    hortensia: 'Hortensia (Hydrangea) er populær for de store blomsterhodene. Bigleaf-hortensia blomstrer på gammelt ved og beskjæres minimalt. PeeGee og Annabelle kan kuttes ned om høsten. Blomstfargen på bigleaf påvirkes av jordsurheten.',
    klematis: 'Klematis finnes i tre grupper med ulik beskjæringstid. Gruppe 1 (alpina): minimal beskjæring, blomstrer på gammel ved. Gruppe 2 (store hybridblomster): lett beskjæring. Gruppe 3 (jackmanii): kuttes ned til 30-50 cm hvert år. Dekk røttene godt.',
    'klematis-gruppe1': 'Klematis gruppe 1 (alpina, macropetala) blomstrer på fjorårets skudd i april-mai. Aldri kraftig beskjær — da mister du blomstringen.',
    'klematis-gruppe3': 'Klematis gruppe 3 (jackmanii, viticella) blomstrer på årets nye skudd fra midsommer. Kuttes ned til 30-50 cm hvert år i februar-mars.',
    blåregn: 'Blåregn (Wisteria) er spektakulær men krevende. Bruker 3-5 år på å etablere seg. To beskjæringer per år er nødvendig. Tålmodig eier belønnes med en av havens vakreste blomstringer.',
    spirea: 'Spirea er en nøysom, hardfør busk som blomstrer rikelig. Hvitblomstrende tidligsorter klippes etter blomstring om sommeren. Lite skadedyrproblemer.',
    magnolia: 'Magnolia blomstrer vakkert tidlig vår på bar kvist, men blomstene er svært frostømfintlige. Velg sen-blomstrende sorter i kalde strøk. Unngå beskjæring — magnolia gror sår dårlig.',
    hengepil: 'Hengepil (Salix x chrysocoma) trives best ved vann og i fuktig jord. Rask vekst — kan bli 8-12 m. Røttene kan skade avløpsrør. Plasser ikke nær rørinstallasjoner.',
    bjørketre: 'Bjørk (Betula) er et norsk ikontre med karakteristisk hvit bark. Bjørkepollen er en sterk allergenkilde i april-mai. Saften kan tappes i april.',
    lavendel: 'Lavendel (Lavandula angustifolia) er tørketålende og trives i mager, godt drenert jord og full sol. Klipp tilbake med 1/3 etter blomstring. Kritisk: aldri klipp ned i gammelt trevirke — den kommer ikke tilbake.',
    solsikke: 'Solsikke (Helianthus annuus) er en rask og enkel ettårsblomst. Sår direkte utendørs etter siste frost. Gigantsorter trenger støtte. La modne hoder stå — fuglene elsker frøene.',
    peon: 'Peon (Paeonia lactiflora) er langlivet med overdådige duftende blomster. Blomstrer i juni. Ikke plant for dypt — øynene skal være 2-3 cm under bakken. Kan stå på samme sted i tiår.',
    tulipan: 'Tulipan (Tulipa) plantes om høsten. La bladene gule naturlig i minst 6 uker etter blomstring. Nye løk hvert år gir rikest blomstring.',
    georgine: 'Georgine (Dahlia) er en luksusblomst med enormt fargespekter. Ta opp knollene etter første frost, tørk og lagre frostfritt. Gjødsle rikelig for best blomstring.',
    luppiner: 'Lupin er en spektakulær staude med fargerike blomsterstøyler. Kortlivet (3-5 år) men sår seg selv. Fixerer nitrogen i jorda. Pass på luseangrep i mai-juni.',
    pelargonium: 'Pelargonium (balkonggran) tåler ikke frost. Sett ut etter 15. mai. Gjødsle ukentlig. Ta inn i september. Overvintres lyst og kjølig (10-15°C).',
    påskelilje: 'Påskelilje (Narcissus) er en av de hardeste løkblomstene. La bladene stå og gule naturlig i minst 6 uker etter blomstring. Giftig for dyr.',
    krokus: 'Krokus er en av de første vårblomstene — dukker opp allerede i februar-mars. Særdeles effektiv i store grupper. Naturaliserer seg godt i gresset.',
    hyasint: 'Hyasint har usedvanlig sterk og behagelig duft. Kan dyrkes innendørs i spesialglass med bare vann for blomstring til jul.',
    fuchsia: 'Fuchsia er en elegant halvskyggeblomst. Tåler ikke frost — ta inn i september. Overvinter mørkt og kjølig (5-8°C). Klipp tilbake til 1/3 i mars.',
    ridderspore: 'Ridderspore (Delphinium) er en av hagenes mest dramatiske planter. Kan nå 2 m. Trenger støtte mot vind. Klipp ned til 30 cm etter første blomstring for høstblomstring.',
    iris: 'Iris (skjeggfri, Iris sibirica m.fl.) er en robust staude med elegante blomster. Trives i fuktig til normal jord. Del klumper hvert 4-5 år.',
    'iris-skjegg': 'Skjeggete iris (Iris germanica) trenger godt drenert jord og full sol. Rhizomene skal ligge halvt over jordoverflaten for å modnes i sol.',
  }
  return descs[key] || 'En plante som trives godt i norske hager med riktig stell og plassering.'
}

