// Hjelpefunksjoner
// ────────────────────────────────────────────────
export const PLANT_MAP = Object.fromEntries(PLANT_DB.map(p => [p.key, p]))

export function getPlant(key) {
  return PLANT_MAP[key] || null
}

export function getPlantsByCategory() {
  const grouped = {}
  CAT_ORDER.forEach(cat => { grouped[cat] = [] })
  PLANT_DB.forEach(p => {
    if (grouped[p.cat]) grouped[p.cat].push(p)
  })
  return grouped
}

export function getMonthlyTasks(plantKeys, month) {
  const tasks = []
  plantKeys.forEach(key => {
    const plant = PLANT_MAP[key]
    if (!plant) return
    const monthTasks = plant.seasonal[month] || []
    monthTasks.forEach((task, idx) => {
      tasks.push({ task, plant: plant.name, emoji: plant.emoji, plantKey: key, idx })
    })
  })
  return tasks
}

